mapper.select:
SELECT a.ID AS "id", b.DICT_TYPE AS "dictType", b.DICT_NAME AS "dictName", a.DICT_VALUE AS "dictValue", a.DICT_LABEL AS "dictLabel", a.DICT_VALUE AS "value", a.DICT_LABEL AS "label" FROM M_DICT_DATA a INNER JOIN M_DICT_TYPE b ON (a.DICT_TYPE=B.DICT_TYPE AND b.STATUS='1' AND a.STATUS='1')
#{dictType,jdbcType=VARCHAR}
ORDER BY a.SORT_NUM, a.DICT_VALUE

SELECT a.ID AS "id", b.DICT_TYPE AS "dictType", b.DICT_NAME AS dictName, a.DICT_VALUE AS "dictValue", a.DICT_LABEL AS "dictLabel", a.DICT_VALUE AS "value", a.DICT_LABEL AS "label" FROM M_DICT_DATA a INNER JOIN M_DICT_TYPE b ON (a.DICT_TYPE=B.DICT_TYPE AND b.STATUS='1' AND a.STATUS='1')
a.DICT_TYPE = #{type,jdbcType=VARCHAR}
ORDER BY a.SORT_NUM, a.DICT_VALUE

select d.id, d.PARENT_ID, d.DEPT_CODE, d.DEPT_NAME, d.ORDER_NO, d.REMARK, d.PARENT_IDS, d.CHIEF, d.STATUS, d.DESCR, d.DEPT_LEVEL, d.DEPT_TYPE, d.DEPT_NO, d.PARENT_DEPT_CODE from sys_dept d
and d.status = #{status}
and d.parent_id=#{parentId}
order by d.ORDER_NO

SELECT a.TYPE_CD, a.CD, a.NM FROM M_CONSTANTS a
#{typeCd, jdbcType=VARCHAR}
ORDER BY a.TYPE_CD, a.SORT_NUM

SELECT DISTINCT MM.ID as "id", MM.MAC_CODE as "macCode", MM.MAC_NAME as "macName", MM.MAC_TYPE_CODE as "macTypeCode", MM.MAC_MODEL_CODE as "macModelCode", MM.DEPT_ID as "deptId", MM.IMEI as "imei", MM.STATUS as "status", MM.CREATE_BY as "createBy", MM.CREATE_TIME as "createTime", MM.UPDATE_BY as "updateBy", MM.UPDATE_TIME as "updateTime", MM.MAC_MODEL_NAME as "macModelName", MMT.MAC_TYPE_NAME as "macTypeName", MM.MAC_CODE as "equipmentNo", MM.ID as "equipmentId", MMT.MAC_TYPE_NAME as "equipmentTypeName", MMT.ID as "equipmentTypeId", MMT.ID as "macTypeId", SD.DEPT_NAME as "deptName" FROM M_MACHINE MM INNER JOIN SYS_DEPT SD ON MM.DEPT_ID = SD.ID LEFT JOIN M_MACHINE_TYPE MMT ON MMT.MAC_TYPE_CODE = MM.MAC_TYPE_CODE
AND MM.MAC_CODE = #{macCode,jdbcType=VARCHAR}
AND MMT.MAC_TYPE_CODE = #{equipmentTypeCode}
AND MM.DEPT_ID = #{deptId}
AND (SD.DEPT_NO like #{deptNo_like,jdbcType=VARCHAR}
${canDispatchDept}
)
ORDER BY MMT.MAC_TYPE_NAME,MM.MAC_CODE
